def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Find the main subject (airport) - typically the one with cityServed, location, or runway-related predicates
    main_subject = None
    for subject, triples_list in subject_map.items():
        if any(p in ["cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel"] for p, _ in triples_list):
            main_subject = subject
            break

    if not main_subject and subject_map:
        main_subject = list(subject_map.keys())[0]

    if not main_subject:
        return "."

    # Group triples by subject and create natural language relationships
    sentence = main_subject
    location_info = {}

    # First, collect location hierarchy information
    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate == "location":
                location_info[subject] = obj
            elif predicate == "country" and subject in location_info.values():
                location_info["country"] = obj
            elif predicate == "isPartOf" and subject in location_info.values():
                location_info["region"] = obj
            elif predicate == "language" and (subject in location_info.values() or subject == location_info.get("country")):
                location_info["language"] = obj

    # Build the sentence with natural relationships
    if "location" in location_info:
        sentence += f" is located in {location_info['location']}"
        if "region" in location_info:
            sentence += f", which is part of {location_info['region']}"
        if "country" in location_info:
            sentence += f" in {location_info['country']}"
        if "language" in location_info:
            sentence += f" where the language is {location_info['language']}"

    # Process remaining triples for the main subject
    for predicate, obj in subject_map[main_subject]:
        if predicate == "cityServed":
            sentence += f" serves the city of {obj}"
        elif predicate == "mayor":
            sentence += f" has a mayor named {obj}"
        elif predicate == "operatingOrganisation":
            sentence += f" is operated by {obj}"
        elif predicate == "elevationAboveTheSeaLevel":
            sentence += f" is {obj} metres above sea level"
        elif predicate == "runwayLength":
            sentence += f" has a runway length of {obj} metres"
        elif predicate == "capital":
            sentence += f" has {obj} as its capital"
        elif predicate == "leader":
            sentence += f" has {obj} as its leader"
        elif predicate == "owner":
            sentence += f" is owned by {obj}"
        elif predicate == "1stRunwayLengthFeet":
            sentence += f" has a first runway length of {obj} feet"
        elif predicate == "1stRunwaySurfaceType":
            sentence += f" has a first runway with {obj} surface"
        elif predicate == "3rdRunwayLengthFeet":
            sentence += f" has a third runway length of {obj} feet"
        elif predicate == "icaoLocationIdentifier":
            sentence += f" has an ICAO location identifier of {obj}"
        elif predicate == "locationIdentifier":
            sentence += f" has a location identifier of {obj}"
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            sentence += f" is {obj} feet above sea level"
        elif predicate == "iataLocationIdentifier":
            sentence += f" has an IATA identifier of {obj}"
        elif predicate == "nativeName":
            sentence += f" has a native name of {obj}"
        elif predicate == "leaderParty":
            sentence += f" has a leader party of {obj}"
        elif predicate == "runwayName":
            sentence += f" has a runway named {obj}"
        elif predicate == "runwaySurfaceType":
            sentence += f" has a runway surface type of {obj}"
        elif predicate == "elevationAboveTheSeaLevelInMetres":
            sentence += f" is {obj} metres above sea level"
        elif predicate == "demonym":
            sentence += f" whose people are called {obj}"
        elif predicate == "officialLanguage":
            sentence += f" has {obj} as its official language"

    # Handle other subjects connected to the main subject (e.g., country, region info already handled above)
    # For any remaining triples not on main_subject but related via location hierarchy, skip unless needed

    return sentence + "."

